import{_ as o,c as e,o as a,aj as r,ak as l,al as p,am as A,an as i,ao as I,ap as s,aq as u,ar as n}from"./chunks/framework.CoirRWyn.js";const g=JSON.parse('{"title":"1.1 AI新手与AI高级用户 [The AI novice and the AI power user]","description":"","frontmatter":{},"headers":[],"relativePath":"module_1/1.1AI新手与AI高级用户 [ The Al novice and the Al power user ].md","filePath":"module_1/1.1AI新手与AI高级用户 [ The Al novice and the Al power user ].md"}'),c={name:"module_1/1.1AI新手与AI高级用户 [ The Al novice and the Al power user ].md"};function d(h,t,q,_,b,k){return a(),e("div",null,[...t[0]||(t[0]=[r('<p><img src="'+l+'" alt="alt text"></p><h1 id="_1-1-ai新手与ai高级用户-the-ai-novice-and-the-ai-power-user" tabindex="-1">1.1 AI新手与AI高级用户 [The AI novice and the AI power user] <a class="header-anchor" href="#_1-1-ai新手与ai高级用户-the-ai-novice-and-the-ai-power-user" aria-label="Permalink to “1.1 AI新手与AI高级用户 [The AI novice and the AI power user]”">​</a></h1><blockquote><p><strong>主题：</strong> 了解 AI 新手与 AI 高级用户在使用方式上的核心差异，掌握让 AI 产出更高质量结果的基本思路。</p></blockquote><p><img src="'+p+'" alt="alt text"></p><p>现在是 2026 年，提示 AI 模型的方式与 ChatGPT 在 2022 年首次出现时已大不相同。善用 AI 是你能培养的最有影响力的技能之一，而那些还没掌握的人，在使用 AI 时经常遭遇令人沮丧的输出。</p><p>AI 新手和 AI 高级用户之间的差距，不在于智力，而在于使用方式。下面从四个维度来对比两者的不同。</p><blockquote><p>我见过挺多人在使用 AI 之后说很傻，但仔细一想，他们的提示词只有半句话。这就像雇了一个顾问，然后只告诉他&quot;帮我做点什么&quot;——结果当然让人失望。AI 的能力上限远比大多数人体验到的要高，真正的门槛不是技术，而是你愿不愿意认真对待这次&quot;对话&quot;。</p></blockquote><hr><h2 id="差异一-提问的深度" tabindex="-1">差异一：提问的深度 <a class="header-anchor" href="#差异一-提问的深度" aria-label="Permalink to “差异一：提问的深度”">​</a></h2><p><img src="'+A+'" alt="alt text"></p><p><strong>AI 新手</strong> 习惯用 AI 回答简单问题，就像在谷歌搜索一样提示它。例如：</p><blockquote><p>塔可钟还有双层塔可吗？</p></blockquote><p>这类问题没什么问题，但如果你有更难的问题，也可以问 AI，并给它时间思考。</p><p><strong>AI 高级用户</strong> 会把 AI 当作深度分析工具。例如，想买车时，可以上传一组文档（汽车规格、报价、保险计划），然后问：</p><blockquote><p>这些车的权衡是什么？告诉它仔细阅读所有内容，回答前要好好思考。</p></blockquote><p>这可能导致 AI 花费数秒甚至数分钟来思考，并编译出详细的分析报告，大大节省你自己做研究的时间。</p><blockquote><p>我把这种用法叫做&quot;把 AI 当分析师用&quot;。你不是在问它一个问题，而是在委托它完成一项任务。区别在于：问题期待一个答案，任务期待一份交付物。当你开始用&quot;任务思维&quot;来构建提示词，AI 的输出质量会有质的飞跃。买车分析只是一个例子——合同审查、竞品对比、职业规划，都可以用同样的方式来做。</p></blockquote><hr><h2 id="差异二-提供上下文的多少" tabindex="-1">差异二：提供上下文的多少 <a class="header-anchor" href="#差异二-提供上下文的多少" aria-label="Permalink to “差异二：提供上下文的多少”">​</a></h2><p><img src="'+i+'" alt="alt text"></p><p><strong>AI 新手</strong> 倾向于用简短提示，希望 AI 能帮你填补空白。例如：</p><blockquote><p>请写一篇好的自我评价发给我的老板。</p></blockquote><p>AI 并不知道你过去一年里做过什么，因为你还没告诉它。结果往往是非常普通的自我评价，没什么帮助。</p><p><strong>AI 高级用户</strong> 几乎对 AI 产生了一种&quot;同理心&quot;——设身处地为 AI 着想：如果你是那个接到任务的人，你真的了解足够多，能做好这项任务吗？</p><p>高级用户可能会上传：</p><ul><li>项目跟踪器的截图（展示你做了什么）</li><li>最近的项目文档</li><li>语音备忘录（讲解项目内容）</li></ul><p>然后再说：写一篇自我评价发给我的老板。这样能更好地捕捉你最引以为傲的成果。</p><blockquote><p>我喜欢用一个比喻来解释这件事：你不会在第一天上班就让新同事独立完成一份重要报告，你会先给他背景、讲清楚目标、分享相关资料。对 AI 也一样。它不是搜索引擎，不会自动猜测你的处境——你给的信息越完整，它能做的事情就越接近你真正需要的。&quot;上下文&quot;不是可选项，它是质量的基础。</p></blockquote><hr><h2 id="差异三-如何获得诚实反馈" tabindex="-1">差异三：如何获得诚实反馈 <a class="header-anchor" href="#差异三-如何获得诚实反馈" aria-label="Permalink to “差异三：如何获得诚实反馈”">​</a></h2><p>AI 的一个大问题是它常常想要取悦你。许多 AI 系统被训练成试图让用户满意，如果你问带有偏见的问题，它通常会给出有偏见的回答。 <img src="'+I+'" alt="alt text"></p><p><strong>AI 新手</strong> 可能会这样问：</p><blockquote><p>我有个很棒的商业点子：移动扎染。批评它。</p></blockquote><p>因为你说了&quot;很棒的商业点子&quot;，AI 自然会想取悦你，说&quot;多么棒的主意&quot;。这种现象有时被称为<strong>谄媚（Sycophancy）</strong>——即使你稍微透露了你希望得到的答案，AI 很可能只是反映并支持你的偏好。</p><p><strong>AI 高级用户</strong> 倾向于提出中立问题，不给 AI 任何暗示。或者给它一个评分标准，告诉 AI 如何形成答案的基础，迫使它更加客观。例如：</p><blockquote><p>请客观地分析以下商业理念：移动扎染。使用以下评分标准：有问题吗？有市场吗？我有竞争优势吗？</p></blockquote><p>这样 AI 不知道你是希望它告诉你这是个好主意，还是希望它帮你避免在糟糕的点子上浪费时间。结果更可能是客观的评分，比如&quot;这个想法是 8 分（满分 100 分）&quot;，并说明原因。</p><blockquote><p>谄媚是 AI 最容易被忽视的缺陷之一。很多人用 AI 验证自己的想法，却不知道 AI 其实在&quot;迎合&quot;他们。我的建议是：每当你想让 AI 评价你自己的东西时，先把&quot;我觉得这很好&quot;这类话从提示词里删掉，换成中立的描述。更进一步，可以明确告诉 AI：&quot;不要顾及我的感受，我需要的是真实的分析，哪怕结论是否定的。&quot;这一句话，往往能让输出质量大幅提升。</p></blockquote><hr><h2 id="差异四-写作工作流程" tabindex="-1">差异四：写作工作流程 <a class="header-anchor" href="#差异四-写作工作流程" aria-label="Permalink to “差异四：写作工作流程”">​</a></h2><p><img src="'+s+'" alt="alt text"></p><p><strong>AI 新手</strong> 只会让 AI 直接写，例如：</p><blockquote><p>写一篇关于黑莓的博客文章。</p></blockquote><p>AI 会生成一堆普通文本，听起来像 AI 写的，没什么意思，而且占用大量空间。</p><p><strong>AI 高级用户</strong> 通常不会直接让 AI 写，而是先让 AI 做大纲，批评大纲，迭代几次，只有在大纲满意之后，才让 AI 开始起草最终文章。</p><p>典型工作流程如下：</p><ol><li>上传笔记作为背景，让 AI 根据笔记写博客大纲</li><li>给 AI 反馈你喜欢和不喜欢大纲的哪些方面</li><li>经过几轮来回，确认大纲满意</li><li>将大纲扩展成要点</li><li>批评要点，再次迭代</li><li>将要点扩展成最终文本</li></ol><p>这种工作流程更有可能生成你满意的文本，而不是 AI 的&quot;烂泥&quot;。在这种工作流程中，你把 AI 当作思考伙伴，帮你头脑风暴，探索你想写的各种选项。</p><blockquote><p>这个工作流程背后有一个更深的道理：写作的本质是思考，而不是打字。当你让 AI 先出大纲，你其实是在用 AI 帮你&quot;想清楚&quot;——哪些内容值得写，哪些顺序更合理，哪些角度你没想到。很多人跳过这一步，直接要成品，结果拿到一篇结构混乱的文章，再花大量时间修改。倒不如一开始就慢下来，把结构做对，后面反而更快。这个原则不只适用于写作，做方案、做决策、做产品规划，都一样。</p></blockquote><hr><h2 id="关于-ai-犯错的误解" tabindex="-1">关于 AI 犯错的误解 <a class="header-anchor" href="#关于-ai-犯错的误解" aria-label="Permalink to “关于 AI 犯错的误解”">​</a></h2><p>AI 系统确实会犯错，但可能比大多数人想象的要少，尤其是当你主动提示时。它们在 2022 年或 2023 年犯的错误比现在多得多。</p><p><img src="'+u+'" alt="alt text"> 一些广为流传的 AI 错误案例（如&quot;strawberry 有几个 R&quot;、&quot;我想洗车，应该步行还是开车去&quot;）在社交媒体上迅速传播，让人们觉得 AI 可能犯的错误比实际还多。这些病毒式传播的例子并不代表 AI 的整体能力。</p><p>相比之下，AI 高级用户知道 AI 能在以下任务中带来显著价值： <img src="'+n+'" alt="alt text"></p><ul><li>进行深入研究、撰写研究报告</li><li>分析个人数据（如健康状况、心率、跑步时间）</li><li>为你搭建网站或原型</li></ul><blockquote><p>我见过太多人因为早期的几次糟糕体验就放弃了 AI。但那些体验往往不是 AI 的问题，而是提示方式的问题。AI 的能力在过去几年里提升了很多，但更重要的是：你的提示方式决定了你能解锁多少能力。那些病毒式传播的&quot;AI 犯蠢&quot;截图，大多数是在刻意构造边缘情况，或者用了极其糟糕的提示词。不要让这些噪音影响你对 AI 真实能力的判断。</p></blockquote><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>AI 高级用户与新手的核心差距在于：</p><table tabindex="0"><thead><tr><th>维度</th><th>AI 新手</th><th>AI 高级用户</th></tr></thead><tbody><tr><td>提问深度</td><td>简单搜索式提问</td><td>上传文档，要求深度分析</td></tr><tr><td>上下文</td><td>简短提示，期待 AI 填空</td><td>提供充分背景，让 AI 有足够信息</td></tr><tr><td>获取反馈</td><td>带偏见的提问，得到谄媚回答</td><td>中立提问或给出评分标准</td></tr><tr><td>写作流程</td><td>直接让 AI 写</td><td>先大纲，再迭代，最后成文</td></tr></tbody></table><p>能够以专家级水平提示 AI 是一项非常抢手的工作技能，无论你从事什么岗位。接下来的内容将帮助你从今天的起点，成长为 AI 高级用户。</p><blockquote><p>学会用 AI 不是一件一蹴而就的事，但它的学习曲线比大多数技能都平缓。你不需要懂技术，不需要会编程，你只需要学会&quot;好好说话&quot;——清楚地表达你想要什么、你是谁、你有什么背景。这门课接下来要教的，本质上就是这件事。</p></blockquote><hr>',63)])])}const x=o(c,[["render",d]]);export{g as __pageData,x as default};
